// --- Multi-Provider Support Card Component ---
const PaymentCard: React.FC<{ 
    lang: Language, 
    title: string, 
    url: string, 
    color: string,
    labelEn: string,
    labelAr: string,
    iconImg?: string,
    className?: string // Added className for better layout control
}> = ({ lang, title, url, color, labelEn, labelAr, iconImg, className = '' }) => {
  const [isHovered, setIsHovered] = useState(false);
  const [isRedirecting, setIsRedirecting] = useState(false);

  const handleClick = (e: React.MouseEvent) => {
    e.preventDefault();
    if (isRedirecting) return;

    setIsRedirecting(true);
    // 2 seconds delay before redirect
    setTimeout(() => {
        window.open(url, '_blank');
        setTimeout(() => setIsRedirecting(false), 1000);
    }, 2000);
  };

  const label = lang === 'en' ? labelEn : labelAr;
  const opening = lang === 'en' ? 'OPENING...' : 'جاري الفتح...';

  return (
    <a 
      href={url} 
      onClick={handleClick}
      onMouseEnter={() => setIsHovered(true)} 
      onMouseLeave={() => setIsHovered(false)} 
      className={`
        group relative block w-full select-none overflow-hidden rounded-[24px] transition-all duration-300 transform border border-white/5
        ${isRedirecting ? 'scale-[1.02] z-50' : 'hover:-translate-y-2 hover:shadow-2xl'}
        ${className}
      `}
      style={{
          boxShadow: isHovered && !isRedirecting ? `0 20px 40px -15px ${color}30` : ''
      }}
    >
        {/* === BACKGROUND GLOW === */}
        <div 
            className="absolute inset-0 opacity-20 transition-opacity duration-500"
            style={{ 
                background: `linear-gradient(135deg, ${color} 0%, transparent 100%)`,
                opacity: isHovered ? 0.4 : 0.1
            }}
        ></div>

        {/* === LUXURY OVERLAYS === */}
        <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-10 mix-blend-overlay"></div>

        {/* === CONTENT === */}
        <div className="relative z-10 p-6 flex flex-col justify-between h-full min-h-[140px]">
            <div className="flex items-center justify-between">
                <div className={`p-3 rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 ${isRedirecting ? 'animate-spin' : ''}`}>
                    {iconImg ? (
                        <img src={iconImg} alt={title} className="w-6 h-6 object-contain" />
                    ) : (
                        <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                        </svg>
                    )}
                </div>
                <div 
                    className={`w-8 h-8 rounded-full border flex items-center justify-center transition-colors ${isHovered ? 'bg-white text-black border-white' : 'border-white/20 text-white/50'}`}
                >
                    <svg className={`w-4 h-4 ${isRTL(lang) ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                </div>
            </div>

            <div className="mt-4">
                <p className={`text-[10px] font-bold tracking-[0.2em] uppercase mb-1 opacity-70`} style={{ color: color }}>
                    {isRedirecting ? opening : label}
                </p>
                <h3 className={`text-2xl font-black text-white tracking-tight ${lang === 'ar' ? 'font-arabic' : ''}`}>
                    {title}
                </h3>
            </div>
        </div>
    </a>
  );
};

