export default function App() {
  const [isHoveringProfile, setIsHoveringProfile] = useState(false);
  const [lang, setLang] = useState<Language>('en');

  const [branding] = useState({
    profileImage: DEFAULT_PROFILE_IMAGE,
    bannerImage: DEFAULT_BACKGROUND_IMAGE
  });
// ... (rest of App component remains unchanged)
  const [socials] = useState<SocialLink[]>(STATIC_SOCIALS);

  const [streamInfo, setStreamInfo] = useState({
    isLive: false,
    viewers: 0,
    title: '',
    category: '',
    tags: [] as string[]
  });

  const t = TRANSLATIONS[lang];
  const isRTL = lang === 'ar';

  useEffect(() => {
    const fetchKickStatus = async () => {
      const timestamp = Date.now();

      const proxyUrls = [
          `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(`https://kick.com/api/v2/channels/${CHANNEL_SLUG}?t=${timestamp}`)}`,
          `https://corsproxy.io/?https://kick.com/api/v2/channels/${CHANNEL_SLUG}?t=${timestamp}`,
          `https://api.allorigins.win/get?url=${encodeURIComponent(`https://kick.com/api/v2/channels/${CHANNEL_SLUG}?t=${timestamp}`)}`
      ];

      let data = null;

      for (const url of proxyUrls) {
          try {
              const res = await fetch(url);
              if (res.ok) {
                  const rawData = await res.json();
                  const parsed = url.includes('allorigins') ? JSON.parse(rawData.contents) : rawData;

                  if (parsed && (parsed.id || parsed.user)) {
                      data = parsed;
                      break; 
                  }
              }
          } catch (e) {
              console.warn(`Fetch failed for proxy: ${url}`);
          }
      }

      if (data) {
          const livestreamData = data.livestream;
          const isLive = livestreamData && livestreamData.is_live === true;

          if (isLive) {
              setStreamInfo({
                  isLive: true,
                  viewers: livestreamData.viewer_count || 0,
                  title: livestreamData.session_title || 'Live Stream',
                  category: livestreamData.categories?.[0]?.name || 'Just Chatting',
                  tags: livestreamData.tags ? livestreamData.tags.map((t: any) => t.name || t) : []
              });
          } else {
              setStreamInfo({
                isLive: false,
                viewers: 0,
                title: '',
                category: '',
                tags: []
              });
          }
      }
    };

    fetchKickStatus();
    const interval = setInterval(fetchKickStatus, 30000); 
    return () => clearInterval(interval);
  }, []); 

  const handleShare = async () => {
    const shareUrl = "https://kick.com/xEiD";
    if (navigator.share) {
      try {
        await navigator.share({ title: t.shareTitle, text: t.shareText, url: shareUrl });
      } catch (err) { console.error('Share failed:', err); }
    } else {
      navigator.clipboard.writeText(shareUrl);
      alert(t.copied);
    }
  };

  const displayTitle = streamInfo.isLive ? streamInfo.title : t.defaultStreamTitle;
  const displayCategory = streamInfo.isLive ? streamInfo.category : t.defaultCategory;

  // Split socials: 
  // 1. General: Kick, Snap, Insta, TikTok, Twitter, WhatsApp (Replaces Email)
