interface LeaderboardCardProps {
  title: string;
  subtitle: string;
  data: LeaderboardEntry[];
  icon: React.ReactNode;
  accentColor: string; // Tailwind color class base (e.g., 'yellow', 'blue', 'rose')
  isMain?: boolean;
  lang: Language;
  t: any;
  delay: number;
  emptyLabel?: string;
  className?: string;
}

const LeaderboardCard: React.FC<LeaderboardCardProps> = ({ title, subtitle, data, icon, accentColor, isMain, lang, t, delay, emptyLabel, className }) => {

    // Dynamic styles based on accent color
    const getAccentStyles = () => {
        if (accentColor === 'yellow') return {
            text: 'text-yellow-200',
            glow: 'shadow-yellow-500/10',
            border: 'group-hover:border-yellow-500/30',
            icon: 'text-yellow-400',
            bg: 'bg-yellow-500/5'
        };
        if (accentColor === 'rose') return {
            text: 'text-rose-200',
            glow: 'shadow-rose-500/10',
            border: 'group-hover:border-rose-500/30',
            icon: 'text-rose-400',
            bg: 'bg-rose-500/5'
        };
        return { // cyan/blue default
            text: 'text-cyan-200',
            glow: 'shadow-cyan-500/10',
            border: 'group-hover:border-cyan-500/30',
            icon: 'text-cyan-400',
            bg: 'bg-cyan-500/5'
        };
    };

    const s = getAccentStyles();

    // Render Empty State
    if (!data || data.length === 0) {
        return (
             <div className={`
                 flex flex-col items-center justify-center p-6 text-center rounded-3xl
                 bg-white/[0.02] backdrop-blur-md border border-dashed border-white/10
                 transition-all duration-500 hover:bg-white/[0.04]
                 ${isMain ? 'lg:-mt-4 z-10 min-h-[350px] md:min-h-[400px]' : 'min-h-[300px] md:min-h-[350px]'}
                 ${className}
             `}
             style={{ animationDelay: `${delay}ms` }}>
                 <div className={`p-4 rounded-full ${s.bg} mb-4 opacity-50`}>
                    {React.cloneElement(icon as React.ReactElement, { className: `w-6 h-6 ${s.icon}` })}
                 </div>
                 <h3 className={`text-sm font-bold text-white/40 mb-1 uppercase tracking-widest`}>{title}</h3>
                 <p className="text-xs text-white/20">{emptyLabel || t.noData}</p>
             </div>
        );
    }

    const sorted = [...data].sort((a,b) => b.quantity - a.quantity).slice(0, 10);

    return (
        <div 
            className={`
                group relative flex flex-col rounded-3xl overflow-hidden transition-all duration-700
                bg-[#0a0a0a]/40 backdrop-blur-xl border border-white/5
                hover:shadow-2xl ${s.glow} ${s.border}
                ${isMain ? 'md:-mt-6 z-20 md:scale-105 shadow-xl' : 'shadow-lg'}
                ${className}
            `}
            style={{ animationDelay: `${delay}ms` }}
        >
             {/* Subtle Gradient Overlay */}
             <div className={`absolute inset-0 bg-gradient-to-b from-white/[0.03] to-transparent pointer-events-none`}></div>

             {/* Header */}
             <div className="relative p-5 md:p-6 flex items-center justify-between border-b border-white/5">
                 <div className="flex items-center gap-4">
                     <div className={`p-2.5 rounded-xl bg-white/[0.03] border border-white/5 ${s.icon} shadow-inner`}>
                         {icon}
                     </div>
                     <div>
                         <h3 className={`text-lg md:text-xl font-bold text-white tracking-tight ${lang === 'ar' ? 'font-arabic' : ''}`}>{title}</h3>
                         <span className={`text-[9px] font-bold uppercase tracking-[0.2em] text-white/30`}>{subtitle}</span>
                     </div>
                 </div>
                 {/* Top Rank Indicator (Subtle) */}
                 <div className="hidden md:block">
                    <span className={`text-[10px] font-mono opacity-20 ${s.text}`}>TOP 10</span>
                 </div>
             </div>

             {/* List */}
             <div className="flex-1 p-2 md:p-3 space-y-1 relative overflow-y-auto max-h-[400px] scrollbar-hide">
                 {sorted.map((entry, idx) => {
                     // Rank Colors
                     let rankColor = 'text-white/40';
                     let rankGradient = '';
                     if (idx === 0) {
                         rankColor = 'text-yellow-400';
                         rankGradient = 'bg-gradient-to-r from-yellow-200 to-yellow-500 bg-clip-text text-transparent';
                     }
                     else if (idx === 1) {
                         rankColor = 'text-gray-300';
                         rankGradient = 'bg-gradient-to-r from-gray-200 to-gray-400 bg-clip-text text-transparent';
                     }
                     else if (idx === 2) {
                         rankColor = 'text-orange-300';
                         rankGradient = 'bg-gradient-to-r from-orange-200 to-orange-400 bg-clip-text text-transparent';
                     }

                     return (
                         <div key={idx} className="flex items-center justify-between p-3 rounded-xl hover:bg-white/[0.03] transition-colors group/row">
                             <div className="flex items-center gap-4 overflow-hidden min-w-0">
                                 <span className={`w-4 text-center text-xs font-black ${rankColor} opacity-80`}>
                                     {idx + 1}
                                 </span>
                                 <div className="flex flex-col min-w-0">
                                     <span className={`text-sm font-bold truncate ${idx < 3 ? 'text-white' : 'text-white/70'} group-hover/row:text-white transition-colors`}>
                                         {entry.username}
                                     </span>
                                 </div>
                             </div>
                             <div className="flex items-center gap-1.5 pl-2">
                                <span className={`text-xs font-black ${idx < 3 ? rankGradient : 'text-white/40'}`}>
                                    {formatNumber(entry.quantity)}
                                </span>
                                {idx === 0 && (
                                    <div className={`w-1 h-1 rounded-full ${s.bg.replace('/5', '')} animate-pulse`}></div>
                                )}
                             </div>
                         </div>
                     );
                 })}
             </div>

             {/* Bottom Fade for Scroll */}
             <div className="absolute bottom-0 left-0 right-0 h-6 bg-gradient-to-t from-black/40 to-transparent pointer-events-none"></div>
        </div>
    );
};

// --- INLINE VIDEO PLAYER COMPONENT ---
interface InlinePlayerProps {
  video: Video;
  onClose: () => void;
}

const InlinePlayer: React.FC<InlinePlayerProps> = ({ video, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const hlsRef = useRef<Hls | null>(null);

  useEffect(() => {
    const videoEl = videoRef.current;
    if (!videoEl || !video.source) return;

    // Use Hls.js if supported
    if (Hls.isSupported()) {
      const hls = new Hls({
        startLevel: -1, // Auto quality
        capLevelToPlayerSize: true,
      });
      hlsRef.current = hls;
      hls.loadSource(video.source);
      hls.attachMedia(videoEl);
      hls.on(Hls.Events.MANIFEST_PARSED, () => {
        const playPromise = videoEl.play();
        if (playPromise !== undefined) {
          playPromise.catch(() => {
             // Autoplay blocked or interrupted - silence error
          });
        }
      });
    } 
    // Fallback for Safari/iOS which has native HLS support
    else if (videoEl.canPlayType('application/vnd.apple.mpegurl')) {
      videoEl.src = video.source;
      videoEl.addEventListener('loadedmetadata', () => {
        const playPromise = videoEl.play();
        if (playPromise !== undefined) {
           playPromise.catch(() => {});
        }
      });
    }

    return () => {
      if (hlsRef.current) {
        hlsRef.current.destroy();
      }
    };
  }, [video.source]);

  return (
    <div className="relative w-full aspect-video bg-black rounded-xl overflow-hidden border border-white/10 shadow-2xl animate-fade-in-up">
        {/* Close/Collapse Button */}
       <button 
         onClick={(e) => {
             e.stopPropagation();
             onClose();
         }}
         className="absolute top-3 right-3 z-20 p-2 rounded-full bg-black/60 backdrop-blur-md text-white/70 hover:text-white hover:bg-black/80 transition-all border border-white/10 shadow-lg group"
         title="Close Player"
       >
         <svg className="w-5 h-5 group-hover:scale-90 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
         </svg>
       </button>

       <video 
         ref={videoRef}
         className="w-full h-full object-contain"
         controls
         playsInline
         poster={video.thumbnail?.url || video.thumbnail?.src || FALLBACK_IMAGE}
         disablePictureInPicture={false}
         controlsList="nodownload" 
       />

       {/* Ambient Glow */}
       <div className="absolute inset-0 bg-kick/5 blur-[50px] pointer-events-none -z-10"></div>
    </div>
  );
};

export const StatsSection: React.FC<StatsSectionProps> = ({ lang }) => {
  // Initialize as null to indicate "loading"
  const [leaderboards, setLeaderboards] = useState<LeaderboardData | null>(null);
  const [clips, setClips] = useState<Clip[] | null>(null);
  const [videos, setVideos] = useState<Video[] | null>(null);
  const [channelInfo, setChannelInfo] = useState<ChannelInfo | null>(null);

  // State for Video Player (Inline ID)
  const [activeVideoId, setActiveVideoId] = useState<number | null>(null);

  const t = {
    followers: lang === 'en' ? 'Followers' : 'متابع',
    topGifters: lang === 'en' ? 'Top Gifters' : 'كبار الداعمين',
    allTime: lang === 'en' ? 'All Time' : 'الأفضل',
    monthly: lang === 'en' ? 'Monthly' : 'شهرياً',
    weekly: lang === 'en' ? 'Weekly' : 'أسبوعياً',
    recentClips: lang === 'en' ? 'Top Clips' : 'أقوى اللقطات',
    recentVods: lang === 'en' ? 'Past Streams' : 'البثوث السابقة',
    views: lang === 'en' ? 'Views' : 'مشاهدة',
    gift: lang === 'en' ? 'Gifts' : 'هدية',
    subBadges: lang === 'en' ? 'Sub Badges' : 'شارات المشتركين',
    noData: lang === 'en' ? 'No Data' : 'لا يوجد بيانات',
    watching: lang === 'en' ? 'Now Playing' : 'جاري المشاهدة',

    // Custom Empty States
    noDataWeekly: lang === 'en' ? 'No active gifters this week' : 'لا يوجد داعمين هذا الأسبوع',
    noDataMonthly: lang === 'en' ? 'No active gifters this month' : 'لا يوجد داعمين لهذا الشهر',
    noDataAllTime: lang === 'en' ? 'No records found' : 'لا يوجد سجلات بعد',
  };

  useEffect(() => {
    const channelSlug = 'xeid';
    const timestamp = Date.now();

    const endpoints = {
      leaderboard: `https://kick.com/api/v2/channels/${channelSlug}/leaderboards`,
      clips: `https://kick.com/api/v2/channels/${channelSlug}/clips`,
      videos: `https://kick.com/api/v2/channels/${channelSlug}/videos`,
      channel: `https://kick.com/api/v2/channels/${channelSlug}`
    };

    const fetchWithProxy = async (url: string) => {
      // Add timestamp to prevent caching from proxies
      const urlWithCacheBuster = `${url}?t=${timestamp}`;

      const proxyUrls = [
         `https://api.allorigins.win/get?url=${encodeURIComponent(urlWithCacheBuster)}`,
         `https://corsproxy.io/?${urlWithCacheBuster}`,
         `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(urlWithCacheBuster)}`
      ];

      for (const proxy of proxyUrls) {
        try {
          const res = await fetch(proxy);
          if (!res.ok) continue;
          const data = await res.json();
          // allorigins returns content as string, others return direct json
          const result = proxy.includes('allorigins') ? JSON.parse(data.contents) : data;
          if (result) return result;
        } catch (e) {
          console.warn(`Proxy failed for ${url}`, e);
        }
      }
      return null;
    };

    // Fetch independently to allow progressive loading
    fetchWithProxy(endpoints.leaderboard).then(data => {
        if (data) {
            // Robust data mapping:
            // 1. Handle if data is wrapped in a "leaderboard" property
            const source = data.leaderboard || data;

            setLeaderboards({
                // Check multiple possible keys for robustness
                gifts: source.gifts || source.all_time || [],
                gifts_week: source.gifts_week || source.weekly || [],
                gifts_month: source.gifts_month || source.gifts_monthly || source.monthly || [] 
            });
        } else {
            setLeaderboards({ gifts: [], gifts_week: [], gifts_month: [] });
        }
    });

    fetchWithProxy(endpoints.clips).then(data => {
        // Kick API for clips usually returns { clips: [...] }
        if (data && data.clips) {
             setClips(data.clips.slice(0, 4));
        } else if (Array.isArray(data)) {
             // Just in case it returns an array directly
             setClips(data.slice(0, 4));
        } else {
             setClips([]); 
        }
    });

    fetchWithProxy(endpoints.videos).then(data => {
        if (data && Array.isArray(data)) setVideos(data.slice(0, 3));
        else setVideos([]);
    });

    fetchWithProxy(endpoints.channel).then(data => {
        if (data) setChannelInfo(data);
        else {
             setChannelInfo({ followers_count: 0, subscriber_badges: [] });
        }
    });

  }, []);

  return (
    <>
      <div className="w-full space-y-16 animate-fade-in-up" style={{ animationDelay: '0.2s' }}>

        {/* --- CHANNEL STATS BAR --- */}
        {channelInfo ? (
          <div className="relative group">
             <div className="absolute inset-0 bg-gradient-to-r from-kick/0 via-kick/5 to-kick/0 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity duration-1000"></div>
             <div className="relative flex items-center justify-between bg-[#080808]/60 backdrop-blur-md border border-white/5 p-8 rounded-[30px] shadow-2xl overflow-hidden hover:border-white/10 transition-colors">

                {/* Background Noise */}
                <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-5 mix-blend-overlay"></div>

                <div className="flex items-center gap-6 relative z-10">
                   <div className="relative">
                       <div className="absolute inset-0 bg-kick blur-xl opacity-20 animate-pulse"></div>
                       <div className="p-4 bg-[#111] text-white rounded-2xl border border-white/10 shadow-lg relative">
                          <KickIcon className="w-10 h-10 text-kick" />
                       </div>
                   </div>
                   <div>
                      <h3 className="text-4xl md:text-5xl font-black text-white tracking-tighter drop-shadow-lg">{formatNumber(channelInfo.followers_count)}</h3>
                      <p className="text-xs text-white/40 uppercase tracking-[0.2em] font-bold mt-1 pl-1">{t.followers}</p>
                   </div>
                </div>

                <div className="hidden sm:flex items-center gap-3 relative z-10">
                   {channelInfo.subscriber_badges && channelInfo.subscriber_badges.length > 0 && (
                       <>
                          <div className="flex flex-col items-end mr-4">
                            <span className="text-[10px] text-white/30 font-bold uppercase tracking-[0.25em]">{t.subBadges}</span>
                            <div className="h-0.5 w-8 bg-kick/50 rounded-full mt-1"></div>
                          </div>
                          <div className="flex gap-2">
                            {channelInfo.subscriber_badges.sort((a,b) => a.months - b.months).map((badge) => (
                                <div key={badge.id} className="relative group/badge transition-transform duration-300 hover:-translate-y-2">
                                    <div className="absolute -inset-2 bg-white/20 blur-md rounded-full opacity-0 group-hover/badge:opacity-100 transition-opacity"></div>
                                    <img 
                                        src={badge.badge_image.src} 
                                        alt={`${badge.months} months`} 
                                        className="w-12 h-12 object-contain drop-shadow-xl relative z-10"
                                        title={`${badge.months} Months`}
                                    />
                                </div>
                            ))}
                          </div>
                       </>
                   )}
                </div>
             </div>
          </div>
        ) : (
          <Skeleton className="h-32 w-full rounded-[30px]" />
        )}

        {/* --- LEADERBOARDS --- */}
        <div className="relative space-y-12">

            {/* Minimal Header */}
