  const [channelInfo, setChannelInfo] = useState<ChannelInfo | null>(null);

  // State for Video Player (Inline ID)
  const [activeVideoId, setActiveVideoId] = useState<number | null>(null);

  const t = {
    followers: lang === 'en' ? 'Followers' : 'متابع',
    topGifters: lang === 'en' ? 'Top Gifters' : 'كبار الداعمين',
    allTime: lang === 'en' ? 'All Time' : 'الأفضل',
    monthly: lang === 'en' ? 'Monthly' : 'شهرياً',
    weekly: lang === 'en' ? 'Weekly' : 'أسبوعياً',
    recentClips: lang === 'en' ? 'Top Clips' : 'أقوى اللقطات',
    recentVods: lang === 'en' ? 'Past Streams' : 'البثوث السابقة',
    views: lang === 'en' ? 'Views' : 'مشاهدة',
    gift: lang === 'en' ? 'Gifts' : 'هدية',
    subBadges: lang === 'en' ? 'Sub Badges' : 'شارات المشتركين',
    noData: lang === 'en' ? 'No Data' : 'لا يوجد بيانات',
    watching: lang === 'en' ? 'Now Playing' : 'جاري المشاهدة',

    // Custom Empty States
    noDataWeekly: lang === 'en' ? 'No active gifters this week' : 'لا يوجد داعمين هذا الأسبوع',
    noDataMonthly: lang === 'en' ? 'No active gifters this month' : 'لا يوجد داعمين لهذا الشهر',
    noDataAllTime: lang === 'en' ? 'No records found' : 'لا يوجد سجلات بعد',
  };

  useEffect(() => {
    const channelSlug = 'xeid';
    const timestamp = Date.now();

    const endpoints = {
      leaderboard: `https://kick.com/api/v2/channels/${channelSlug}/leaderboards`,
      clips: `https://kick.com/api/v2/channels/${channelSlug}/clips`,
      videos: `https://kick.com/api/v2/channels/${channelSlug}/videos`,
      channel: `https://kick.com/api/v2/channels/${channelSlug}`
    };

    const fetchWithProxy = async (url: string) => {
      // Add timestamp to prevent caching from proxies
      const urlWithCacheBuster = `${url}?t=${timestamp}`;

      const proxyUrls = [
         `https://api.allorigins.win/get?url=${encodeURIComponent(urlWithCacheBuster)}`,
         `https://corsproxy.io/?${urlWithCacheBuster}`,
         `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(urlWithCacheBuster)}`
      ];

      for (const proxy of proxyUrls) {
        try {
          const res = await fetch(proxy);
          if (!res.ok) continue;
          const data = await res.json();
          // allorigins returns content as string, others return direct json
          const result = proxy.includes('allorigins') ? JSON.parse(data.contents) : data;
          if (result) return result;
        } catch (e) {
          console.warn(`Proxy failed for ${url}`, e);
        }
      }
      return null;
    };

    // Fetch independently to allow progressive loading
    fetchWithProxy(endpoints.leaderboard).then(data => {
        if (data) {
            // Robust data mapping:
            // 1. Handle if data is wrapped in a "leaderboard" property
            const source = data.leaderboard || data;

            setLeaderboards({
                // Check multiple possible keys for robustness
                gifts: source.gifts || source.all_time || [],
                gifts_week: source.gifts_week || source.weekly || [],
                gifts_month: source.gifts_month || source.gifts_monthly || source.monthly || [] 
            });
        } else {
            setLeaderboards({ gifts: [], gifts_week: [], gifts_month: [] });
        }
    });

    fetchWithProxy(endpoints.clips).then(data => {
        // Kick API for clips usually returns { clips: [...] }
        if (data && data.clips) {
             setClips(data.clips.slice(0, 4));
        } else if (Array.isArray(data)) {
             // Just in case it returns an array directly
             setClips(data.slice(0, 4));
        } else {
             setClips([]); 
        }
    });

    fetchWithProxy(endpoints.videos).then(data => {
        if (data && Array.isArray(data)) setVideos(data.slice(0, 3));
        else setVideos([]);
    });

    fetchWithProxy(endpoints.channel).then(data => {
        if (data) setChannelInfo(data);
        else {
             setChannelInfo({ followers_count: 0, subscriber_badges: [] });
        }
    });

  }, []);

  return (
    <>
      <div className="w-full space-y-16 animate-fade-in-up" style={{ animationDelay: '0.2s' }}>

        {/* --- CHANNEL STATS BAR --- */}
        {channelInfo ? (
