          `https://api.allorigins.win/get?url=${encodeURIComponent(`https://kick.com/api/v2/channels/${CHANNEL_SLUG}?t=${timestamp}`)}`
      ];

      let data = null;

      for (const url of proxyUrls) {
          try {
              const res = await fetch(url);
              if (res.ok) {
                  const rawData = await res.json();
                  const parsed = url.includes('allorigins') ? JSON.parse(rawData.contents) : rawData;

                  if (parsed && (parsed.id || parsed.user)) {
                      data = parsed;
                      break; 
                  }
              }
          } catch (e) {
