import Pusher from 'pusher-js';

// 1. دالة لجلب معرف الشات (Chatroom ID) لأننا لا نستطيع الاتصال بدونه
const getChatroomId = async (channelSlug: string) => {
  const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(`https://kick.com/api/v2/channels/${channelSlug}`)}`;

  try {
    const response = await fetch(proxyUrl);
    const rawData = await response.json();
    const data = JSON.parse(rawData.contents);
    return data.chatroom.id; // هذا هو الرقم السري المطلوب للاتصال
  } catch (error) {
    console.error("خطأ في جلب بيانات القناة", error);
    return null;
  }
};

// 2. دالة الاتصال بالشات المباشر
const connectToChat = async (chatroomId: string) => {
  // إعداد Pusher
  const pusher = new Pusher('32cbd69e4b950bf97679', {
    cluster: 'us2',
    forceTLS: true
  });

  // الاشتراك في "قناة" الشات الخاصة بالستريمر
  const channel = pusher.subscribe(`chatrooms.${chatroomId}.v2`);

  // الاستماع لحدث "رسالة جديدة"
  channel.bind('App\\Events\\ChatMessageEvent', (data: any) => {
    console.log("وصلت رسالة جديدة:", {
      user: data.sender.username,
      text: data.content,
      color: data.sender.identity.color,
      badges: data.sender.identity.badges
    });

    // هنا يتم تحديث الـ State في React لعرض الرسالة
  });

  return { pusher, channel };
};
3. كيف يعمل هذا الكود في الخلفية؟ (الشرح المبسط)

إذا أردت دمج هذا المنطق في ملفك، فإنه يتبع هذا التسلسل:

تخطي الحماية (CORS Proxy): لأن متصفحك يمنع الاتصال المباشر بـ Kick API من موقع خارجي، نستخدم allorigins أو corsproxy كوسيط.

معرفة الـ ID: الستريمر اسمه xeid ولكن سيرفر الشات يفهم رقم (مثلاً 123456). الكود يذهب ويبحث عن هذا الرقم أولاً.

فتح الأنبوب (Pusher Connection): بمجرد الحصول على الرقم، يفتح المتصفح "أنبوب" اتصال دائم مع Pusher.

الاستماع (Binding): الكود ينتظر حدثاً اسمه ChatMessageEvent. بمجرد أن يكتب أي شخص في Kick، يرسل السيرفر إشارة تصل لهذا الكود فوراً.

ملاحظة تقنية من الكود الثاني (App.tsx):

الكود الثاني (الملف الطويل) يقوم بجلب حالة البث (أونلاين أو أوفلاين) بنفس الطريقة (عبر Proxy)، بينما الكود الأول مخصص فقط للشات. لكي يعمل الشات عندك، يجب أن تتأكد من تثبيت مكتبة pusher عبر الأمر:
npm install pusher-js

وانت زبطه

